import React, { useState, useEffect } from "react";
import TopNavBar from "../components/TopNavBar";
import Header from "../components/Header";
import { api } from "../api";
import { FiSearch } from "react-icons/fi";

// Dummy data for Payments Due & Investor Performance
const paymentsDue = [
  {
    name: "Alice",
    amount: 4000,
    day: "Today",
    img: "https://randomuser.me/api/portraits/women/75.jpg",
  },
  {
    name: "Bob",
    amount: 2400,
    day: "Today",
    img: "https://randomuser.me/api/portraits/men/32.jpg",
  },
  {
    name: "Krishna",
    amount: 3000,
    day: "Tomorrow",
    img: "https://randomuser.me/api/portraits/men/23.jpg",
  },
  {
    name: "Nita",
    amount: 6000,
    day: "Tomorrow",
    img: "https://randomuser.me/api/portraits/women/18.jpg",
  },
];

const investorPerformance = [
  {
    name: "Suresh Prabha",
    date: "03.07.2024",
    amount: "₹ 200k",
    rate: "1.5%",
    count: "3.0k",
    img: "https://randomuser.me/api/portraits/men/12.jpg",
  },
  {
    name: "Jagrati Thakur",
    date: "03.07.2024",
    amount: "₹ 100k",
    rate: "3.0%",
    count: "5k",
    img: "https://randomuser.me/api/portraits/women/32.jpg",
  },
  {
    name: "Shiva",
    date: "03.07.2024",
    amount: "₹ 100k",
    rate: "2.0%",
    count: "4k",
    img: "https://randomuser.me/api/portraits/men/29.jpg",
  },
];

export default function Homepage() {
  return (
    <div
      style={{ background: "#EAEDFB", minHeight: "100vh", paddingBottom: 80 }}
    >
      <Header />
      <TopNavBar />

      <div
        style={{
          maxWidth: 470,
          margin: "0 auto",
          background: "#F3F6FC",
          borderRadius: 32,
          padding: 22,
          boxShadow: "0 2px 16px #7286D340",
        }}
      >
        {/* Search Bar */}
        <div
          style={{
            background: "#fff",
            borderRadius: 14,
            padding: "9px 12px 9px 0",
            boxShadow: "0 1px 4px #D1D1D155",
            marginBottom: 22,
            display: "flex",
            alignItems: "center",
          }}
        >
          <FiSearch style={{ marginLeft: 15, color: "#AAA", fontSize: 18 }} />
          <input
            placeholder="Search name, keyword..."
            style={{
              width: "100%",
              border: "none",
              fontSize: 17,
              outline: "none",
              background: "transparent",
              marginLeft: 8,
            }}
          />
        </div>

        {/* Ready to Redeem */}
        <div
          style={{
            background: "#fff",
            borderRadius: 16,
            padding: 18,
            marginBottom: 22,
            boxShadow: "0 1px 4px #D1D1D110",
            display: "flex",
            flexDirection: "column",
          }}
        >
          <span style={{ color: "#888", fontSize: 13, marginBottom: 2 }}>
            Available amount
          </span>
          <div
            style={{
              color: "#51A654",
              fontWeight: 700,
              fontSize: 23,
              marginBottom: 5,
            }}
          >
            ₹ 45,987.15
          </div>
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
            }}
          >
            <span
              style={{
                color: "#5D5FEF",
                fontSize: 14,
              }}
            >
              Total redeem: ₹ 30,000.00
            </span>
            <button
              style={{
                background: "#5D5FEF",
                color: "#fff",
                border: "none",
                borderRadius: 15,
                padding: "7px 21px",
                fontWeight: 600,
                fontSize: 15,
                cursor: "pointer",
              }}
            >
              Redeem Now
            </button>
            <span
              style={{
                color: "#5D5FEF",
                fontSize: 13,
                marginLeft: 10,
                cursor: "pointer",
              }}
            >
              View history
            </span>
          </div>
        </div>

        {/* Payments Due */}
        <div style={{ marginBottom: 22 }}>
          <div style={{ fontWeight: 600, marginBottom: 9, color: "#222" }}>
            Payments Due
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 25 }}>
            {paymentsDue.map((pay, i) => (
              <div key={i} style={{ textAlign: "center" }}>
                <img
                  src={pay.img}
                  alt=""
                  style={{
                    width: 47,
                    height: 47,
                    borderRadius: "50%",
                    objectFit: "cover",
                    marginBottom: 2,
                    border: "2px solid #fff",
                    boxShadow: "0 2px 7px #b0b0b055",
                  }}
                />
                <div
                  style={{
                    fontWeight: 700,
                    fontSize: 13,
                    color: "#E84D4F",
                    marginBottom: 1,
                  }}
                >
                  ₹ {pay.amount}
                </div>
                <div
                  style={{ color: "#5D5FEF", fontWeight: 500, fontSize: 12 }}
                >
                  {pay.day}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Add Transactions Button */}
        <button
          style={{
            width: "100%",
            background: "#5D5FEF",
            color: "#fff",
            border: "none",
            borderRadius: 20,
            fontWeight: 700,
            padding: "12px 0",
            fontSize: 16,
            marginBottom: 32,
          }}
        >
          + Add Transactions
        </button>

        {/* Investor Performance */}
        <div
          style={{
            background: "#fff",
            borderRadius: 14,
            padding: 18,
            marginBottom: 22,
            boxShadow: "0 1px 5px #d1d8ed21",
          }}
        >
          <div style={{ fontWeight: 600, color: "#222", marginBottom: 6 }}>
            Investor Performance
          </div>
          {investorPerformance.map((inv, i) => (
            <div
              key={i}
              style={{
                display: "flex",
                alignItems: "center",
                marginBottom: 11,
              }}
            >
              <img
                src={inv.img}
                alt=""
                style={{
                  width: 38,
                  height: 38,
                  borderRadius: "50%",
                  objectFit: "cover",
                  marginRight: 12,
                }}
              />
              <div style={{ flex: 1 }}>
                <div
                  style={{ fontWeight: 600, color: "#3649ca", marginBottom: 2 }}
                >
                  {inv.name}
                </div>
                <div style={{ fontSize: 12, color: "#acacac" }}>{inv.date}</div>
              </div>
              <div style={{ textAlign: "right" }}>
                <div style={{ fontWeight: 700 }}>{inv.amount}</div>
                <div style={{ fontSize: 11, color: "#8fadc7" }}>
                  {inv.rate} ({inv.count})
                </div>
              </div>
            </div>
          ))}
          <div style={{ textAlign: "center" }}>
            <span
              style={{
                color: "#5D5FEF",
                fontWeight: 600,
                cursor: "pointer",
                fontSize: 14,
              }}
            >
              View All
            </span>
          </div>
        </div>
      </div>
    </div>
  );
}
